INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (1, 'CA22c5f1f76a36783df5aa62c7d5c9b3ae', '1', TRUE, TRUE, 'alto', 'positivo', 'Lead confirmou interesse em receber proposta e informou orçamento de R$ 10.000,00 mensais. Aceitou agendar uma reunião para apresentação.', 'agendar_reuniao', 'Confere. Torno já, R$ 10.000 por mês. Acho legal. Você fala da onde? Claro, com certeza.', 'Alô, Vinicius? Aqui é o Lucas, da V4 Company. Tudo bem? Notei que você tem interesse em receber uma proposta da nossa assessoria, confere? Que ótimo! Para eu preparar algo direcionado, você poderia me dizer se já tem um orçamento definido para investir em marketing? Perfeito, Vinicius. Vou encaminhar a proposta por e mail e, se você preferir, podemos marcar uma rápida reunião para apresentar. O que acha? Eu sou da V4 Company, como te falei. Estamos no Brasil inteiro. Posso te mandar por e mail o convite para a reunião, para conversarmos melhor?', '2026-05-04T19:36:04.420325+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (2, 'CA9f1a0465341a6af9890d79b226874388', '1', TRUE, TRUE, 'medio', 'positivo', 'Cliente confirmou interesse em receber proposta por e-mail.', 'enviar_email', 'Alô. Alô, tudo bem? Ah, sim.', 'Olá, boa tarde, falo com o Kaique Aqui Alô, Kaique? Empresa. Recebi é da Minha seu contato pelo site e queria saber se você tem interesse em receber uma proposta da nossa assessoria V4 Company. Que ótimo! Você receber por e-mail ou WhatsApp? prefere', '2026-05-04T21:43:11.863801+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (3, 'CAdd59c54ce06ccad3f898f7a050d3df6f', '1', FALSE, TRUE, 'sem_interesse', 'neutro', 'O cliente informou que não tem interesse em receber a proposta nem em agendar uma conversa no momento.', 'nao_contatar', 'Alô. Alô. Caramba. Acho que não, hein? Hum, ah, não é melhor, não. Melhor, não.', 'Alô, Kaique? Oi, Kaique, tudo o agente Company, mais pedindo da V4 bom? preencheu Sou um formulário uma proposta você sobre informações por e em receber mail? tem interesse Você assessoria. Ah, entendi! Sem problemas. Você gostaria de receber por outro meio, ou prefere que a gente agende uma conversa?', '2026-05-04T21:45:43.302486+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (4, 'CA95b28887d43e142749d52ce0c639fc1a', 'c7a43424-5a73-44d7-a9c7-97da251b58a9', TRUE, TRUE, 'medio', 'neutro', 'Cliente confirmou interesse e solicitou informações via WhatsApp.', 'enviar_whatsapp', 'Tenho, sim.', 'Alô, é o Kaique Nascimento? Sou da V4 Company, você preencheu um formulário recentemente. Queria saber se ainda tem interesse em saber mais sobre a nossa assessoria? Que ótimo! Você prefere que a gente te envie mais informações por WhatsApp ou por e-mail? Ou de repente já marcar uma conversa com o nosso time?', '2026-05-04T22:45:09.874428+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (5, 'CAec0aaade41bb2a49b79edfbb9b4c6540', '1', TRUE, TRUE, 'medio', 'positivo', 'Cliente confirmou interesse no software de gestão e agendou reunião para a próxima terça-feira às 14h. Demonstrou humor positivo durante a conversa.', 'agendar_reuniao', 'Eu não quero saber onde. Eu tenho, sim, Mares. Eu quero entender o que que você falou que eu não cadastrei. Eu me cadastrei onde? Sim. Mas tu quer tirar essa sala mesmo? Qual o produto? Sim. Pode ser final de semana. perder é melhor.', 'Olá Kaique Nascimento, tudo bem? Vi que você se cadastrou na {{metodo}}. Eu queria ver se podemos marcar uma reunião para podermos trazer melhor o produto para você. Você tem disponibilidade essa semana? Ah, peço desculpas se não fui claro! Na verdade, eu estava propondo um local virtual, né, uma reunião online. Mas me diga, você teria disponibilidade para conversarmos um pouco sobre o produto, mesmo que brevemente? Ou você não tem interesse nesse tipo de solução? Ah, sim! Consta aqui no meu sistema que você demonstrou interesse através do nosso site, preenchendo um cadastro. Às vezes o nome do método pode ter ficado confuso. Mas você lembra de ter buscado informações sobre algo do tipo? E sobre a reunião, você teria um tempinho para conversarmos? Ótimo! Que bom que você lembra. Para essa reunião, qual seria o melhor horário para você? E que dia da semana fica melhor? Assim eu já agendo aqui com um de nossos especialistas. É sobre um software de gestão, para ajudar a organizar os processos da sua empresa. Você gostaria de agendar uma conversa para ver como ele funciona? Que dia fica melhor para você? Perfeito. Essa semana, você tem algum dia específico com horário mais livre? Ou prefere sugerir algum horário para a semana que vem? Combinado, então na semana que vem! Algum dia específico ou período do dia que seja melhor para você? Por exemplo, na terça à tarde, ou na quinta de manhã? Ótimo, então vamos marcar para a tarde. O que você acha da próxima terça-feira, dia 12, às 14 horas? Fica bom para você?', '2026-05-04T23:49:29.572653+00:00', 'bc44702c-8b88-4d14-bdbb-ad2f5dddab4f') ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (7, 'CAdfcc84c74511ff9645a5e8fbeca5d4a0', '7824c098-2183-4965-865e-bc4708c7a5c4', TRUE, TRUE, 'alto', 'positivo', 'Cliente confirmou interesse na assessoria, informou orçamento de R$ 5000 e prefere receber a proposta pelo WhatsApp.', 'enviar_whatsapp', 'Sim. É, cruel. Dá opinião para Sim. Não. R$ 5.000', 'Alô, Renan? Aqui é o Leo da V4. Tudo bem? Vi que você mandou um contato pra gente. Você ainda tem interesse em receber uma proposta da nossa assessoria? Ah, legal! Pra gente montar algo bem focado no que você precisa, qual é o principal desafio comercial de vocês hoje? E você teria uma ideia de orçamento disponível pra isso? Ótimo. E para te mandar a proposta certinha, qual é o melhor e-mail para contato? Ou você prefere que eu te envie pelo WhatsApp?', '2026-05-05T16:56:50.750145+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (8, 'CAf7b39fd9bd10493235c14705d0ece014', 'c7a43424-5a73-44d7-a9c7-97da251b58a9', FALSE, FALSE, 'incerto', 'neutro', 'O contato parece estar ocupado ou em outra conversa e não respondeu diretamente. Call inconclusiva.', 'revisar_manualmente', 'detenção para filho e quando o filho for maior, você vai conseguir aumentar ainda mais a receita? E aí, você vai ficar Pô, beleza. É, qual o nome da empresa do seu projeto? Acho que a gente tem que voltar a falar do seu projeto. Entrando no Google', 'Opa, tudo bom? É o Kaique que tá falando? Aqui é o Kaique da Tech Corp? Aqui é', '2026-05-05T20:19:02.836954+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (9, 'CA04ac84581bb8d07d10baf6650af84fdb', 'fd23ce72-6e06-40d4-9da3-de68bbb5ab71', TRUE, TRUE, 'medio', 'neutro', 'Cliente não pode falar agora e prefere que mande mensagem antes de ligar na próxima semana.', 'enviar_whatsapp', 'Ixi, espera aí. Alô. Tudo bem e você? Agora eu não tenho. Putz, essa semana eu não consigo.', 'Alô, Gisele? Aqui é da V4 Company. Tudo bom? Tô ligando rapidinho para falar sobre uma ideia Tudo bem? Só pra confirmar, tô falando com a Gisele mesmo? Joia! Eu tô ligando pra gente bater um papo sobre umas ideias pra Leite Tech. Você tem uns minutinhos? Tranquilo! Qual seria um horário bom pra te retornar? Entendi. Semana que vem fica melhor? Ou prefere que eu te mande uma mensagem?', '2026-05-08T22:13:03.430682+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (10, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'fd23ce72-6e06-40d4-9da3-de68bbb5ab71', FALSE, TRUE, 'medio', 'neutro', 'Gisele já tem estrutura de marketing, mas aceitou receber material por e-mail para avaliar com mais tempo.', 'enviar_email', 'Alô. Alô. Alô. Não, tá mudo. Você tá me tirando agora. Mas onde você conseguiu o seu telefone? Quem me garante que é tudo certinho? Mas você quer falar sobre o que mesmo? Ah, mas eu já tenho tudo montado. Ah, a gente já tá conversando. Mas seria a ligação mesmo? Porque eu não tenho tempo.', 'Olá, Gisele? Tudo bom? Sou da V4 Company. Liguei para falar sobre marketing digital focado em empresas como a Leite Tech. Você tem uns minutos para conversar agora? Ah, essa informação vem da nossa base de dados, mas não se preocupa, é tudo certinho. Você teria um tempinho agora pra gente bater um papo? Entendo a sua preocupação. É sobre como a V4 pode te ajudar a conseguir mais clientes pra Leite Tech usando estratégias de marketing digital. Você teria interesse em saber um pouco mais sobre como a gente faz? Que bom que você já tem uma estrutura! A gente poderia pensar em como otimizar o que você já tem pra gerar ainda mais resultados. Toparia uma conversa rápida pra gente falar sobre isso? Verdade! Mas eu digo um papo mais aprofundado, sabe? Talvez uma reunião com um especialista pra te mostrar possibilidades mais específicas pra Leite Tech. O que acha de agendarmos? Pode ser uma call rápida de 15 minutos só pra te mostrar algumas possibilidades. Ou se preferir, eu posso te mandar um material por e-mail pra você ver com calma. O que funciona melhor pra você?', '2026-05-08T22:15:40.955678+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO call_results (id, call_sid, lead_id, confirmado, pessoa_correta, interesse, humor, resumo, proxima_acao, transcricao_usuario, transcricao_agente, criado_em, agent_id) VALUES (11, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'a153527b-26c6-42a7-9149-cfc3f55cdaaa', TRUE, TRUE, 'medio', 'neutro', 'Cliente confirmou interesse e solicitou o envio da proposta por e-mail.', 'enviar_email', 'Alô. Tenho.', 'Alô? Oi, Pedro, tudo bem? Aqui é o agente da V4 Company. Tô te ligando pra saber se você ainda tem interesse em receber aquela proposta sobre assessoria. Você tem um minutinho? Desculpa, acho que o sinal Opa! Então, você quer que eu te envie a proposta por e-mail ou você prefere marcar uma conversa rapidinha pra gente detalhar melhor?', '2026-05-11T22:17:32.166688+00:00', NULL) ON CONFLICT DO NOTHING;
