INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (342, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Alô. Não, tá mudo.', '2026-05-08T22:14:10.508011+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (343, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Você tá me tirando agora.', '2026-05-08T22:14:12.102042+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (344, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Olá, Gisele? Tudo bom? Sou da V4 Company. Liguei para falar sobre marketing digital focado em empresas como a Leite Tech. Você tem uns minutos para conversar agora?', '2026-05-08T22:14:15.690513+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (345, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Mas onde você conseguiu o seu telefone?', '2026-05-08T22:14:25.032674+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (346, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Ah, essa informação vem da nossa base de dados, mas não se preocupa, é tudo certinho. Você teria um tempinho agora pra gente bater um papo?', '2026-05-08T22:14:27.994396+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (347, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Quem me garante que é tudo certinho? Mas você quer falar sobre o que mesmo?', '2026-05-08T22:14:38.158396+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (348, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Entendo a sua preocupação. É sobre como a V4 pode te ajudar a conseguir mais clientes pra Leite Tech usando estratégias de marketing digital. Você teria interesse em saber um pouco mais sobre como a gente faz?', '2026-05-08T22:14:42.454218+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (349, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Ah, mas eu já tenho tudo montado.', '2026-05-08T22:14:54.494822+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (350, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Que bom que você já tem uma estrutura! A gente poderia pensar em como otimizar o que você já tem pra gerar ainda mais resultados. Toparia uma conversa rápida pra gente falar sobre isso?', '2026-05-08T22:14:58.095086+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (351, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Ah, a gente já tá conversando.', '2026-05-08T22:15:08.054982+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (352, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Verdade! Mas eu digo um papo mais aprofundado, sabe? Talvez uma reunião com um especialista pra te mostrar possibilidades mais específicas pra Leite Tech. O que acha de agendarmos?', '2026-05-08T22:15:11.707978+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (353, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Mas seria a ligação mesmo? Porque eu não tenho tempo.', '2026-05-08T22:15:23.954956+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (354, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Pode ser uma call rápida de 15 minutos só pra te mostrar algumas possibilidades. Ou se preferir, eu posso te mandar um material por e-mail pra você ver com calma. O que funciona melhor pra você?', '2026-05-08T22:15:27.562493+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (355, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'user', 'Ah! Eu quero o material por e-mail. Aí eu olho quando der tempo.', '2026-05-08T22:15:41.743397+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (356, 'CAe4e2eb84623c18dc666cf9c9cb27a37a', 'agent', 'Perfeito, Gisele! Vou te mandar um e-mail com alguns detalhes. Muito obrigado pela atenção e um ótimo dia!', '2026-05-08T22:15:45.009664+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (357, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'agent', 'Alô? Oi, Pedro, tudo bem? Aqui é o agente da V4 Company. Tô te ligando pra saber se você ainda tem interesse em receber aquela proposta sobre assessoria. Você tem um minutinho?', '2026-05-11T22:17:11.997617+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (358, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'user', 'Alô.', '2026-05-11T22:17:18.628978+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (359, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'agent', 'Desculpa, acho que o sinal', '2026-05-11T22:17:20.221196+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (360, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'user', 'Tenho.', '2026-05-11T22:17:21.619105+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (361, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'agent', 'Opa! Então, você quer que eu te envie a proposta por e-mail ou você prefere marcar uma conversa rapidinha pra gente detalhar melhor?', '2026-05-11T22:17:23.524344+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (362, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'user', '우리 메일', '2026-05-11T22:17:32.137445+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (363, 'CA5e3158bbce6c30476c6a2fcca8dc8695', 'agent', 'Fechado então, Pedro! Vou te mandar por e-mail ainda hoje. Obrigado pela atenção e um abraço!', '2026-05-11T22:17:34.307694+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (364, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Alô. Alô.', '2026-05-12T19:56:09.590758+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (365, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'Olá, Gustavo Estorgato, tudo bem? Aqui é do time de vendas. Vi que você se cadastrou no método, e eu queria ver se a gente consegue marcar uma reunião para te apresentar melhor o produto. Você tem disponibilidade essa semana?', '2026-05-12T19:56:10.814667+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (366, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Não tenho.', '2026-05-12T19:56:25.684464+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (367, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'Entendo. E para a semana que vem, teria algum dia ou horário melhor para você? Assim eu já verifico a agenda por aqui.', '2026-05-12T19:56:28.377589+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (368, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Vai ficar chorando, menina? Me explica melhor do que que é essa essa ligação.', '2026-05-12T19:56:37.241424+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (369, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'Claro! O nosso produto é focado em ajudar a aumentar a eficiência da sua equipe, e a gente gostaria de te mostrar em detalhes como funciona. Por acaso você é a pessoa que toma as decisões sobre esse tipo de ferramenta na sua empresa?', '2026-05-12T19:56:41.78491+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (370, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Mas eu nem sei do que que você tá falando.', '2026-05-12T19:56:53.311137+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (373, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'O seu cadastro foi realizado recentemente, provavelmente em algum formulário online ou anúncio nosso. Você não se lembra? De qualquer forma, se tiver interesse, a gente pode agendar uma conversa para eu te passar mais detalhes. O que acha?', '2026-05-12T19:57:16.576281+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (376, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Não, não pode Não pode me explicar por aqui mesmo?', '2026-05-12T19:57:36.186273+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (379, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'asynccall:salvar_resultado_ligacao{confirmado:false,humor:neutro,interesse:alto,pessoa_correta:true,proxima_acao:revisar_manualmente,resumo:Cliente demonstrou interesse, mas solicitou agendamento para o passado ("ontem às 2 horas"). Necessário contato manual para reagendar.Ah, para ontem', '2026-05-12T19:57:58.146799+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (371, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'Peço desculpas se não fui claro! Nós somos da empresa X e desenvolvemos uma plataforma que ajuda a gerenciar e otimizar processos de vendas, por exemplo. O objetivo da reunião é justamente te mostrar como ela pode te ajudar. Você acha que faria sentido pra você?', '2026-05-12T19:56:58.327834+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (372, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Entendi, mas eu eu me cadastrei nisso quanto?', '2026-05-12T19:57:12.476933+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (374, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Mmm. Não lembro, não.', '2026-05-12T19:57:24.001269+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (375, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'Sem problemas! Às vezes acontece. Mas mesmo assim, você teria interesse em conhecer um pouco mais? Podemos marcar uma conversa rápida, sem compromisso. O que acha?', '2026-05-12T19:57:27.758713+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (377, 'CA899f668fe3555bda3718e5d53bd29ba1', 'agent', 'Eu até posso te dar uma visão geral, mas numa conversa por vídeoconferência ou reunião, a gente consegue te mostrar a plataforma funcionando, tirar suas dúvidas específicas e até personalizar a apresentação para o seu negócio. É bem mais produtivo, sabe? O que você acha? Uns 15 minutinhos são suficientes.', '2026-05-12T19:57:41.643163+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (378, 'CA899f668fe3555bda3718e5d53bd29ba1', 'user', 'Ponte, entendi, entendi. Então, pode marcar para ontem às 2 horas, por favor.', '2026-05-12T19:57:56.275284+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (380, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'agent', 'Opa, tudo bem? É o Kaique da Tech Corp?', '2026-05-14T19:56:15.1004+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (381, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'user', 'Alô.', '2026-05-14T19:56:16.508383+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (382, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'agent', 'Oi, Kaique, aqui é da V4 Company.', '2026-05-14T19:56:18.792871+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (383, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'user', 'Tudo certo?', '2026-05-14T19:56:19.47884+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (384, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'agent', 'Tudo ótimo! Aqui é o Caio da V4 Company, vi que você demonstrou interesse na assessoria. Você teria cinco minutinhos pra gente conversar', '2026-05-14T19:56:22.433665+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (385, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'user', 'O cara já tá respondendo na mesma.', '2026-05-14T19:56:24.917644+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (386, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'agent', 'Alô? Kaique, tá me ouvindo?', '2026-05-14T19:56:27.278667+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (387, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'user', 'Oi.', '2026-05-14T19:56:30.52984+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (388, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'agent', 'Oi! Acho que a ligação caiu. Tava te falando que sou da V4, você preencheu um formulário pra saber mais sobre a assessoria, lembra? Quer que eu te mande mais detalhes por WhatsApp?', '2026-05-14T19:56:33.643728+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (389, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'user', 'de línea de los alimentos.', '2026-05-14T19:56:42.174878+00:00') ON CONFLICT DO NOTHING;
INSERT INTO transcripts (id, call_sid, role, texto, ts) VALUES (390, 'CA1db3a36396684cc8cb29a2b99b7f59e2', 'agent', 'Ah, tranquilo! Você poderia falar um pouco sobre como andam as vendas da Tech Corp hoje? Pra gente entender se a assessoria faz sentido.', '2026-05-14T19:56:45.628172+00:00') ON CONFLICT DO NOTHING;
